  isRefreshing: boolean;
  skeletonCount: number;
  screenWidth: number;
  formatDate: (iso?: string) => string;
  handleGoBack: () => void;
  handleOpenFilters: () => void;
  handleDetailsOrders: (
    transactionId: string,
    type?: string,
    icon?: string,
    status?: string,
    origination?: string
  )=> void;
  handleRefresh: () => void;
}

